 17→import { loadOnboardingSummary } from "../onboarding/onboarding-state";
 18→import { chatComponentSystemPrompt } from "./chat-component-system-prompt";
 19→import type { GraphEntityRecord } from "../extraction/types";
 20→
 21→export type DiscussedEntityContext = {
 22→  kind: string;
 23→  name: string;
 24→  status?: string;
