 40→type ChatContextLoaders = {
 41→  listConversationEntities: typeof listConversationEntities;
 42→  listWorkspaceProjectSummaries: typeof listWorkspaceProjectSummaries;
 43→  listWorkspaceRecentDecisions: typeof listWorkspaceRecentDecisions;
 44→  listWorkspaceOpenQuestions: typeof listWorkspaceOpenQuestions;
 45→  listWorkspaceOpenObservations: typeof listWorkspaceOpenObservations;
 46→  loadOnboardingSummary: typeof loadOnboardingSummary;
