 49→export async function buildChatContext(input: {
 50→  surreal: Surreal;
 51→  conversationRecord: RecordId<"conversation", string>;
 52→  workspaceRecord: RecordId<"workspace", string>;
 53→  loaders?: ChatContextLoaders;
 54→  inheritedEntityIds?: RecordId[];
 55→  discussesRecord?: RecordId;
 56→  userMessageEmbedding?: number[];
 57→}): Promise<ChatContext> {
 58→  const loaders = input.loaders ?? {
 59→    listConversationEntities,
 60→    listWorkspaceProjectSummaries,
 61→    listWorkspaceRecentDecisions,
 62→    listWorkspaceOpenQuestions,
 63→    listWorkspaceOpenObservations,
 64→    loadOnboardingSummary,
 65→  };
 66→
 67→  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations, onboardingSummary] = await Promise.all([
 68→    loaders.listConversationEntities({
 69→      surreal: input.surreal,
 70→      conversationRecord: input.conversationRecord,
 71→      workspaceRecord: input.workspaceRecord,
 72→      limit: 60,
 73→      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 74→        ? { inheritedEntityIds: input.inheritedEntityIds }
 75→        : {}),
 76→    }),
 77→    loaders.listWorkspaceProjectSummaries({
 78→      surreal: input.surreal,
 79→      workspaceRecord: input.workspaceRecord,
 80→      limit: 20,
 81→    }),
 82→    loaders.listWorkspaceRecentDecisions({
 83→      surreal: input.surreal,
 84→      workspaceRecord: input.workspaceRecord,
 85→      limit: 12,
 86→    }),
 87→    loaders.listWorkspaceOpenQuestions({
 88→      surreal: input.surreal,
 89→      workspaceRecord: input.workspaceRecord,
 90→      limit: 12,
 91→    }),
 92→    loaders.listWorkspaceOpenObservations({
 93→      surreal: input.surreal,
 94→      workspaceRecord: input.workspaceRecord,
 95→      limit: 10,
 96→    }),
 97→    loaders.loadOnboardingSummary(input.surreal, input.workspaceRecord),
 98→  ]);
 99→
100→  // Cross-conversation entity enrichment: find workspace entities relevant to the user's message
101→  let relevantEntities: RankedEntity[] | undefined;
102→  if (input.userMessageEmbedding) {
103→    const queryEmbedding = input.userMessageEmbedding;
104→    const conversationEntityIds = new Set(
105→      conversationEntities.map((e) => e.id),
106→    );
107→    const ranked = await searchEntitiesByEmbedding({
108→      surreal: input.surreal,
109→      workspaceRecord: input.workspaceRecord,
110→      queryEmbedding,
111→      limit: 15,
112→    });
113→    const filtered = ranked.filter((e) => !conversationEntityIds.has(e.id));
114→    if (filtered.length > 0) {
115→      relevantEntities = filtered.slice(0, 10);
116→    }
117→  }
118→
119→  let discussedEntity: DiscussedEntityContext | undefined;
120→  if (input.discussesRecord) {
121→    const entityRecord = input.discussesRecord as GraphEntityRecord;
122→    const name = await readEntityName(input.surreal, entityRecord);
