124→      const row = await input.surreal.select<Record<string, unknown>>(entityRecord);
125→      discussedEntity = {
126→        kind: entityRecord.table.name,
127→        name,
128→        ...(row && typeof row.status === "string" ? { status: row.status } : {}),
129→      };
130→    }
131→  }
132→
133→  return {
134→    conversationEntities,
135→    relevantEntities,
136→    workspaceSummary: {
137→      projects,
138→      recentDecisions,
139→      openQuestions,
140→      openObservations,
141→    },
142→    onboardingSummary,
143→    discussedEntity,
144→  };
145→}
