148→  if (entities.length === 0) {
149→    return "- none";
150→  }
151→
152→  return entities
153→    .slice(0, 20)
154→    .map((entity) => `- ${entity.kind}: ${entity.name} (confidence ${entity.confidence.toFixed(2)})`)
