165→function formatWorkspaceSummary(context: ChatContext): string {
166→  const { projects, recentDecisions, openQuestions, openObservations } = context.workspaceSummary;
167→
168→  const lines: string[] = [];
169→
170→  // Projects: keep names since they're needed for routing
171→  if (projects.length === 0) {
172→    lines.push("- Projects: none");
173→  } else {
174→    lines.push(`- Projects: ${projects.map((p) => p.name).join(", ")}`);
175→  }
176→
177→  // Decisions: count by status
178→  if (recentDecisions.length === 0) {
179→    lines.push("- Decisions: none");
180→  } else {
181→    const statusCounts = new Map<string, number>();
182→    for (const d of recentDecisions) {
183→      statusCounts.set(d.status, (statusCounts.get(d.status) ?? 0) + 1);
184→    }
185→    const breakdown = [...statusCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
186→    lines.push(`- Decisions: ${recentDecisions.length} (${breakdown})`);
187→  }
188→
189→  // Questions: just count
190→  lines.push(`- Open questions: ${openQuestions.length}`);
191→
192→  // Observations: count by severity
193→  if (openObservations.length === 0) {
194→    lines.push("- Observations: none");
195→  } else {
196→    const severityCounts = new Map<string, number>();
197→    for (const o of openObservations) {
198→      severityCounts.set(o.severity, (severityCounts.get(o.severity) ?? 0) + 1);
199→    }
200→    const breakdown = [...severityCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
201→    lines.push(`- Observations: ${openObservations.length} (${breakdown})`);
202→  }
203→
204→  return lines.join("\n");
205→}
