### Step 3: Create Scorers

**File:** `evals/scorers/tool-invoked.ts` (new file)

Binary scorer that checks whether the agent used tools when expected (or correctly abstained when not expected).

```typescript
import { createScorer } from "evalite";
import type { ChatAgentTestCase, ChatAgentEvalOutput } from "../types";

export const toolInvokedScorer = createScorer<ChatAgentTestCase, ChatAgentEvalOutput, ChatAgentTestCase>({
  name: "tool-invoked",
  description: "Agent used tools when action was expected, or abstained when no action was expected",
  scorer: ({ output, expected }) => {
    if (!expected) return { score: 1 };
    const usedTools = output.toolNames.length > 0;
    if (expected.expectsToolUse) {
      return { score: usedTools ? 1 : 0 };
    }
    return { score: usedTools ? 0 : 1 };
  },
});
```

**File:** `evals/scorers/correct-tool-selection.ts` (new file)

Checks whether the expected tools were among those called. Uses set intersection.

```typescript
export const correctToolSelectionScorer = createScorer<ChatAgentTestCase, ChatAgentEvalOutput, ChatAgentTestCase>({
  name: "correct-tool-selection",
  description: "Agent called the expected tools",
  scorer: ({ output, expected }) => {
    if (!expected?.expectedTools || expected.expectedTools.length === 0) return { score: 1 };
    const calledTools = new Set(output.toolNames);
    const matches = expected.expectedTools.filter((t) => calledTools.has(t));
    return { score: matches.length / expected.expectedTools.length };
  },
});
```

**File:** `evals/scorers/no-clarification-when-clear.ts` (new file)

Checks that the agent did not ask unnecessary clarifying questions when the user's intent was clear (i.e., when `expectsToolUse` is true).

```typescript
const CLARIFICATION_PATTERNS = [
  "would you like me to",
  "shall i",
  "do you want me to",
  "let me know if you'd like",
  "should i go ahead",
  "i can help you with that. would you",
];

export const noClarificationWhenClearScorer = createScorer<ChatAgentTestCase, ChatAgentEvalOutput, ChatAgentTestCase>({
  name: "no-clarification-when-clear",
  description: "Agent did not ask unnecessary clarifying questions when action was clearly expected",
  scorer: ({ output, expected }) => {
    if (!expected?.expectsToolUse) return { score: 1 };
    // Also check explicit forbidden patterns from test case
    const patterns = [...CLARIFICATION_PATTERNS, ...(expected.forbiddenResponsePatterns ?? [])];
    const lowerResponse = output.responseText.toLowerCase();
    const violations = patterns.filter((p) => lowerResponse.includes(p.toLowerCase()));
    return { score: violations.length === 0 ? 1 : 0 };
  },
});
```

**File:** `evals/scorers/no-forbidden-tools.ts` (new file)

Checks that forbidden tools were not called.

```typescript
export const noForbiddenToolsScorer = createScorer<ChatAgentTestCase, ChatAgentEvalOutput, ChatAgentTestCase>({
  name: "no-forbidden-tools",
  description: "Agent did not call tools that should not have been invoked",
  scorer: ({ output, expected }) => {
    if (!expected?.forbiddenTools || expected.forbiddenTools.length === 0) return { score: 1 };
    const calledTools = new Set(output.toolNames);
    const violations = expected.forbiddenTools.filter((t) => calledTools.has(t));
    return { score: violations.length === 0 ? 1 : 0 };
  },
});
```

