### Step 5: Create Main Eval File

**File:** `evals/chat-agent.eval.ts` (new file)

Structure follows the analytics eval pattern. Key decisions:

- **Inline test cases** (not a separate JSON file) -- there are only 6-8 cases and they benefit from proximity to the eval logic
- **No caching** on first iteration -- the focus is catching behavioral regression, and each run should hit the real model. Caching can be added later if iteration speed becomes a problem.
- **PM agent model**: created from `PM_AGENT_MODEL` env var or falls back to `EXTRACTION_MODEL` (matching the production config pattern in `config.ts` line 49-51)
- **Analytics deps**: the analytics agent model and analyticsSurreal are provided to `runChatAgent` because tools include `invoke_analytics_agent`. Use the root surreal connection as `analyticsSurreal` for simplicity (no analytics-specific queries are expected in these test cases).

```typescript
// Pseudocode structure:

import { evalite } from "evalite";
import { Factuality } from "autoevals";
import { beforeAll, afterAll } from "vitest";
import { runChatAgent } from "../app/src/server/chat/handler";
import { setupEvalRuntime, teardownEvalRuntime, seedUserMessage } from "./eval-test-kit";
import { seedChatAgentTestData } from "./chat-agent-seed-data";
import { toolInvokedScorer } from "./scorers/tool-invoked";
import { correctToolSelectionScorer } from "./scorers/correct-tool-selection";
import { noClarificationWhenClearScorer } from "./scorers/no-clarification-when-clear";
import { noForbiddenToolsScorer } from "./scorers/no-forbidden-tools";

let runtime, seedResult, pmAgentModel, analyticsAgentModel;

beforeAll(async () => {
  runtime = await setupEvalRuntime("chat-agent");
  seedResult = await seedChatAgentTestData(runtime.surreal);
  // Create PM model (fallback to extraction model)
  pmAgentModel = openrouter(pmModelId);
  analyticsAgentModel = openrouter(analyticsModelId);
}, 120_000);

afterAll(async () => {
  await teardownEvalRuntime(runtime);
}, 120_000);

const cases: ChatAgentTestCase[] = [
  // ... 8 test cases as detailed below
];

evalite("Chat Agent Behavioral Correctness", {
  data: cases.map((c) => ({ input: c, expected: c })),
  task: async (input) => runChatAgentCase(input),
  scorers: [
    toolInvokedScorer,
    correctToolSelectionScorer,
    noClarificationWhenClearScorer,
    noForbiddenToolsScorer,
    responseContainsScorer,  // inline, checks expectedResponseContains
    factualityScorer,        // inline, uses autoevals Factuality
  ],
  columns: ({ input, output, scores }) => [
    { label: "Case", value: input.id },
    { label: "Tools", value: output.toolNames.join(", ") || "(none)" },
    { label: "Invoked", value: formatScore(scores, "tool-invoked") },
    { label: "Correct", value: formatScore(scores, "correct-tool-selection") },
    { label: "NoClarify", value: formatScore(scores, "no-clarification-when-clear") },
    { label: "NoForbid", value: formatScore(scores, "no-forbidden-tools") },
  ],
});

async function runChatAgentCase(testCase: ChatAgentTestCase): Promise<ChatAgentEvalOutput> {
  const messageRecord = await seedUserMessage(runtime.surreal, seedResult.conversationRecord, testCase.userMessage);

  // Seed conversation history if provided
  if (testCase.conversationHistory) {
    await seedConversationContext(runtime.surreal, seedResult.conversationRecord, testCase.conversationHistory);
  }

  const result = await runChatAgent({
    surreal: runtime.surreal,
    model: runtime.chatAgentModel,
    pmAgentModel,
    analyticsAgentModel,
    analyticsSurreal: runtime.surreal,  // reuse root connection
    embeddingModel: runtime.embeddingModel,
    embeddingDimension: runtime.config.embeddingDimension,
    extractionModelId: runtime.config.extractionModelId,
    extractionModel: runtime.extractionModel,
    extractionStoreThreshold: runtime.config.extractionStoreThreshold,
    conversationRecord: seedResult.conversationRecord,
    workspaceRecord: seedResult.workspaceRecord,
    currentMessageRecord: messageRecord,
    latestUserText: testCase.userMessage,
    messages: [
      ...(testCase.conversationHistory ?? []),
      { role: "user", text: testCase.userMessage },
    ],
    onToken: () => {},
  });

  return {
    caseId: testCase.id,
    userMessage: testCase.userMessage,
    responseText: result.text,
    toolCalls: result.toolCalls,
    toolNames: [...new Set(result.toolCalls.map((tc) => tc.name))],
    success: true,
  };
}
```

