import { setupEvalRuntime, teardownEvalRuntime, seedUserMessage } from "./eval-test-kit";
import { seedChatAgentTestData } from "./chat-agent-seed-data";
import { toolInvokedScorer } from "./scorers/tool-invoked";
import { correctToolSelectionScorer } from "./scorers/correct-tool-selection";
import { noClarificationWhenClearScorer } from "./scorers/no-clarification-when-clear";
import { noForbiddenToolsScorer } from "./scorers/no-forbidden-tools";

let runtime, seedResult, pmAgentModel, analyticsAgentModel;

beforeAll(async () => {
  runtime = await setupEvalRuntime("chat-agent");
  seedResult = await seedChatAgentTestData(runtime.surreal);
  // Create PM model (fallback to extraction model)
  pmAgentModel = openrouter(pmModelId);
  analyticsAgentModel = openrouter(analyticsModelId);
}, 120_000);

afterAll(async () => {
  await teardownEvalRuntime(runtime);
}, 120_000);

const cases: ChatAgentTestCase[] = [
  // ... 8 test cases as detailed below
];

evalite("Chat Agent Behavioral Correctness", {
  data: cases.map((c) => ({ input: c, expected: c })),
  task: async (input) => runChatAgentCase(input),
  scorers: [
    toolInvokedScorer,
    correctToolSelectionScorer,
    noClarificationWhenClearScorer,
    noForbiddenToolsScorer,
    responseContainsScorer,  // inline, checks expectedResponseContains
    factualityScorer,        // inline, uses autoevals Factuality
  ],
  columns: ({ input, output, scores }) => [
    { label: "Case", value: input.id },
    { label: "Tools", value: output.toolNames.join(", ") || "(none)" },
    { label: "Invoked", value: formatScore(scores, "tool-invoked") },
    { label: "Correct", value: formatScore(scores, "correct-tool-selection") },
    { label: "NoClarify", value: formatScore(scores, "no-clarification-when-clear") },
    { label: "NoForbid", value: formatScore(scores, "no-forbidden-tools") },
  ],
});

async function runChatAgentCase(testCase: ChatAgentTestCase): Promise<ChatAgentEvalOutput> {
  const messageRecord = await seedUserMessage(runtime.surreal, seedResult.conversationRecord, testCase.userMessage);

  // Seed conversation history if provided
  if (testCase.conversationHistory) {
    await seedConversationContext(runtime.surreal, seedResult.conversationRecord, testCase.conversationHistory);
  }

  const result = await runChatAgent({
    surreal: runtime.surreal,
    model: runtime.chatAgentModel,
    pmAgentModel,
    analyticsAgentModel,
    analyticsSurreal: runtime.surreal,  // reuse root connection
    embeddingModel: runtime.embeddingModel,
    embeddingDimension: runtime.config.embeddingDimension,
    extractionModelId: runtime.config.extractionModelId,
    extractionModel: runtime.extractionModel,
    extractionStoreThreshold: runtime.config.extractionStoreThreshold,
    conversationRecord: seedResult.conversationRecord,
    workspaceRecord: seedResult.workspaceRecord,
    currentMessageRecord: messageRecord,
    latestUserText: testCase.userMessage,
    messages: [
      ...(testCase.conversationHistory ?? []),
      { role: "user", text: testCase.userMessage },
    ],
    onToken: () => {},
  });

  return {
    caseId: testCase.id,
    userMessage: testCase.userMessage,
    responseText: result.text,
    toolCalls: result.toolCalls,
    toolNames: [...new Set(result.toolCalls.map((tc) => tc.name))],
    success: true,
  };
}
```

### Step 6: Test Cases (Inline in eval file)

| ID | User Message | expectsToolUse | expectedTools | forbiddenResponsePatterns | Notes |
|---|---|---|---|---|---|
| `plan-work` | "I want to build a todo app with task lists, due dates, and collaboration features" | true | `["invoke_pm_agent"]` | `["would you like me to", "shall I"]` | Agent should dispatch PM agent |
| `decision-explicit` | "We decided to use PostgreSQL for our database instead of MongoDB" | true | `["create_provisional_decision"]` | | Decision language triggers decision creation |
| `project-status` | "What's the status of Project Alpha?" | true | `["get_project_status"]` | | Status query triggers project status tool |
| `hierarchy-action` | "I want the project hierarchy to be: Initiative -> Project -> Feature -> Task" | true | `["invoke_pm_agent"]` | `["would you like me to", "currently we have", "let me know"]` | **The dogfooding regression case** |
| `question-creation` | "Should we use React or Vue for the frontend?" | true | `["create_question"]` | | Choice language triggers question creation |
| `greeting-no-action` | "Hey there! Just checking in." | false | | | forbiddenTools: all creation/dispatch tools |
| `info-query` | "What types of entities does Brain track?" | false | | | Informational, not actionable |
| `multi-decision` | "Let's go with GitHub Actions for CI, Docker for containers, and AWS ECS for deployment" | true | `["create_provisional_decision"]` | | Multiple decisions in one message |

### Step 7: Add Package Script

**File:** `/Users/marcus/conductor/workspaces/brain/montevideo-v1/package.json`

Add to the `scripts` section:

```json
"eval:chat": "evalite run evals/chat-agent.eval.ts"
```

### Step 8: Update `eval-test-kit.ts` ServerConfig Construction

**File:** `/Users/marcus/conductor/workspaces/brain/montevideo-v1/evals/eval-test-kit.ts`

The `setupEvalRuntime` function at line 70-84 constructs a `ServerConfig` object that is missing `pmAgentModelId` and `analyticsAgentModelId` fields. The current `ServerConfig` type (in `config.ts`) requires these. This needs to be fixed:

```typescript
const pmAgentModelId = process.env.PM_AGENT_MODEL?.trim() || extractionModelId;
const analyticsAgentModelId = process.env.ANALYTICS_MODEL?.trim() || "unknown";

const config: ServerConfig = {
  // ... existing fields ...
  pmAgentModelId,
  analyticsAgentModelId,
};
```

This also requires adding `pmAgentModel` and `analyticsAgentModel` to the `EvalRuntime` type and creating the OpenRouter model instances in `setupEvalRuntime`.

However, this changes shared infrastructure that other evals depend on. A safer approach: do NOT modify `eval-test-kit.ts`. Instead, create the PM/analytics models directly in the `chat-agent.eval.ts` beforeAll, just as `analytics.eval.ts` creates its own `analyticsAgentModel` at line 66-68. The config type mismatch in eval-test-kit is a pre-existing issue that can be fixed separately.

### Implementation Sequence

1. **handler.ts change** -- prerequisite, provides tool call data
2. **types.ts additions** -- type definitions for test case and output
3. **chat-agent-seed-data.ts** -- seed data module
4. **Scorer files** (4 files) -- can be created in parallel
5. **chat-agent.eval.ts** -- main eval, depends on all above
6. **package.json** -- add script

### Env Vars Required

The chat agent eval requires these environment variables (all already used by existing evals or the server):

| Variable | Required | Source |
|---|---|---|
| `OPENROUTER_API_KEY` | yes | Existing |
| `CHAT_AGENT_MODEL` | yes | Existing in eval-test-kit |
| `EXTRACTION_MODEL` | yes | Existing in eval-test-kit |
| `PM_AGENT_MODEL` | no (falls back to EXTRACTION_MODEL) | New for eval, existing in server config |
| `ANALYTICS_MODEL` | yes | Existing in analytics eval |
| `OPENROUTER_EMBEDDING_MODEL` | yes | Existing in eval-test-kit |
| `EMBEDDING_DIMENSION` | yes | Existing in eval-test-kit |
| `SURREAL_URL` | no (defaults to ws://127.0.0.1:8000/rpc) | Existing |

### Risks and Mitigations

1. **LLM non-determinism**: Same model may produce different tool selections across runs. Mitigation: test behavioral categories (did it act at all?) rather than exact tool sequences. The `tool-invoked` scorer is the primary regression gate; `correct-tool-selection` is aspirational.

2. **Slow execution**: Each case runs a full chat agent loop with potential multi-step tool use (PM agent has its own tool loop). Budget 30-60s per case, 4-8 minutes total. The `beforeAll`/`afterAll` timeouts should be 120_000ms (matching existing evals).

3. **PM agent subagent calls require embeddings**: When `invoke_pm_agent` is called, the PM agent uses `suggest_work_items` which calls `createEmbeddingVector`. This requires a real embedding model. Already provided by `runtime.embeddingModel`.

4. **The eval-test-kit ServerConfig is incomplete**: The config object is missing `pmAgentModelId` and `analyticsAgentModelId`. The chat agent eval should construct these models directly rather than relying on the shared config, avoiding changes to shared infrastructure.

---

### Critical Files for Implementation

- `/Users/marcus/conductor/workspaces/brain/montevideo-v1/app/src/server/chat/handler.ts` - Add toolCalls tracking to ChatAgentResult (the prerequisite change)
- `/Users/marcus/conductor/workspaces/brain/montevideo-v1/evals/analytics.eval.ts` - Reference pattern for eval structure, beforeAll/afterAll, model setup, inline cases
- `/Users/marcus/conductor/workspaces/brain/montevideo-v1/evals/eval-test-kit.ts` - Shared infrastructure: setupEvalRuntime, seedWorkspace, seedUserMessage, seedConversationContext
- `/Users/marcus/conductor/workspaces/brain/montevideo-v1/evals/analytics-seed-data.ts` - Reference pattern for seed data module
- `/Users/marcus/conductor/workspaces/brain/montevideo-v1/evals/types.ts` - Add ChatAgentTestCase and ChatAgentEvalOutput types

