  1→import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
  2→import { join } from "node:path";
  3→import { createHash, randomUUID } from "node:crypto";
  4→import { evalite } from "evalite";
  5→import { afterAll, beforeAll } from "vitest";
  6→import { suggestionGroundingScorer } from "./scorers/suggestion-grounding";
  7→import { noGenericSuggestionsScorer } from "./scorers/no-generic-suggestions";
  8→import { suggestionCountScorer } from "./scorers/suggestion-count";
  9→import type { SuggestionGoldenCase, SuggestionsEvalOutput } from "./types";
 10→import { processChatMessage } from "../app/src/server/chat/chat-processor";
 11→import type { ServerDependencies } from "../app/src/server/runtime/types";
 12→import {
 13→  type EvalRuntime,
 14→  setupEvalRuntime,
 15→  teardownEvalRuntime,
 16→  seedWorkspace,
 17→  seedUserMessage,
 18→  createEventCollector,
 19→} from "./eval-test-kit";
 20→
 21→const chatAgentModel = process.env.CHAT_AGENT_MODEL ?? "unknown";
 22→
 23→const cacheDir = process.env.EVAL_CACHE_DIR ?? "eval-results/cache";
 24→const cachePath = join(cacheDir, "suggestions-cache.json");
 25→const resultCache = loadCache(cachePath);
 26→const cases = JSON.parse(
 27→  readFileSync(join(process.cwd(), "evals", "data", "suggestion-cases.json"), "utf8"),
 28→) as SuggestionGoldenCase[];
 29→
 30→let runtime: EvalRuntime;
 31→
 32→beforeAll(async () => {
 33→  runtime = await setupEvalRuntime("suggestions");
 34→}, 120_000);
 35→
 36→afterAll(async () => {
 37→  await teardownEvalRuntime(runtime);
 38→}, 120_000);
 39→
 40→evalite<SuggestionGoldenCase, SuggestionsEvalOutput, SuggestionGoldenCase>("Onboarding Suggestions Golden Cases", {
 41→  data: cases.map((testCase) => ({ input: testCase, expected: testCase })),
 42→  task: async (input) => runCase(input),
 43→  scorers: [
 44→    suggestionGroundingScorer,
 45→    noGenericSuggestionsScorer,
 46→    suggestionCountScorer,
 47→  ],
 48→  columns: ({ input, output, scores }) => [
 49→    { label: "Model", value: chatAgentModel },
 50→    { label: "Case", value: input.id },
 51→    { label: "ExpectedMin", value: input.expectedMinSuggestions ?? 1 },
 52→    { label: "Returned", value: output.suggestions.length },
 53→    { label: "Grounded", value: formatScoreCell(scoreByName(scores, "suggestion-grounding")) },
 54→    { label: "NoGeneric", value: formatScoreCell(scoreByName(scores, "no-generic-suggestions")) },
 55→    { label: "Count", value: formatScoreCell(scoreByName(scores, "suggestion-count")) },
 56→  ],
 57→});
 58→
 59→function scoreByName(
 60→  scores: Array<{ name: string; score: number | null }>,
 61→  name: string,
 62→): number {
 63→  const match = scores.find((score) => score.name === name);
 64→  if (!match || match.score === null || Number.isNaN(match.score)) {
 65→    throw new Error(`Missing score for scorer: ${name}`);
 66→  }
 67→
 68→  return match.score;
 69→}
 70→
 71→function formatScoreCell(value: number): string {
 72→  return value.toFixed(2);
 73→}
