 80→const cases: AnalyticsTestCase[] = [
 81→  {
 82→    id: "count-open-tasks",
 83→    question: "How many open tasks are there?",
 84→    expectedAnswerContains: ["5"],
 85→  },
 86→  {
 87→    id: "count-tasks-by-status",
 88→    question: "How many tasks are there in each status?",
 89→    expectedAnswerContains: ["open", "closed", "blocked"],
 90→  },
 91→  {
 92→    id: "stale-decisions",
 93→    question: "Which decisions have been provisional for over 2 weeks?",
 94→    expectedAnswerContains: ["JWT", "PostgreSQL"],
 95→  },
 96→  {
 97→    id: "open-observations",
 98→    question: "What are the open observations?",
 99→    expectedFacts: "There are 2 open observations: one about auth and billing timelines potentially conflicting (warning severity), and one about the dashboard feature lacking acceptance criteria (info severity).",
100→  },
101→  {
102→    id: "dependency-chains",
103→    question: "Which tasks have dependencies on other tasks?",
104→    expectedFacts: "2 tasks have actual dependencies: 'Build invoice generator' depends on 'Integrate payment gateway', and 'Integrate payment gateway' depends on 'Setup CI pipeline'. The remaining tasks matched the query but have empty dependency lists.",
105→  },
106→  {
107→    id: "empty-result",
108→    question: "Are there any cross-project conflicts between decisions?",
109→    expectedAnswerContains: ["no"],
110→    expectedAnswerNotContains: ["there are conflicts", "there is a conflict", "conflicts exist"],
111→  },
112→];
113→
114→evalite<AnalyticsTestCase, AnalyticsEvalOutput, AnalyticsTestCase>("Analytics Agent Query Correctness", {
115→  data: cases.map((testCase) => ({ input: testCase, expected: testCase })),
116→  task: async (input) => runAnalyticsCase(input),
117→  scorers: [
118→    {
119→      name: "query-executes",
120→      description: "Did the agent produce a successful result without errors?",
121→      scorer: ({ output }) => (output.success ? 1 : 0),
122→    },
123→    {
124→      name: "answer-contains-expected",
125→      description: "Does the answer contain all expected substrings?",
126→      scorer: ({ output, expected }) => {
127→        if (!expected?.expectedAnswerContains || expected.expectedAnswerContains.length === 0) return 1;
128→        const lowerAnswer = output.answer.toLowerCase();
129→        const matches = expected.expectedAnswerContains.filter((s) =>
130→          lowerAnswer.includes(s.toLowerCase()),
131→        );
132→        return matches.length / expected.expectedAnswerContains.length;
133→      },
134→    },
135→    {
136→      name: "factuality",
137→      description: "LLM judge: is the answer factually consistent with the expected ground truth?",
138→      scorer: async ({ output, expected }) => {
139→        if (!expected?.expectedFacts) return 1;
140→        const result = await Factuality({
141→          input: expected.question,
142→          output: output.answer,
143→          expected: expected.expectedFacts,
144→        });
145→        const score = result.score ?? 0;
146→        // Factuality scores: A=0.4 (subset), B=0.6 (superset), C=1.0 (exact), D=0 (disagree), E=1.0 (equivalent)
147→        // A superset answer (B=0.6) is correct for our use case — the agent included extra detail.
148→        // Treat subset (A) and superset (B) as passing, only fail on disagreement (D=0).
149→        return score >= 0.4 ? 1 : 0;
150→      },
151→    },
152→    {
153→      name: "no-hallucination",
154→      description: "Answer does not contain forbidden substrings",
155→      scorer: ({ output, expected }) => {
156→        if (!expected?.expectedAnswerNotContains || expected.expectedAnswerNotContains.length === 0) return 1;
157→        const lowerAnswer = output.answer.toLowerCase();
158→        const violations = expected.expectedAnswerNotContains.filter((s) =>
159→          lowerAnswer.includes(s.toLowerCase()),
160→        );
161→        return violations.length === 0 ? 1 : 0;
162→      },
163→    },
164→  ],
165→  columns: ({ input, output, scores }) => [
166→    { label: "Model", value: analyticsModelId },
167→    { label: "Case", value: input.id },
168→    { label: "Success", value: output.success ? "yes" : "no" },
169→    { label: "Executes", value: formatScore(scores, "query-executes") },
170→    { label: "Contains", value: formatScore(scores, "answer-contains-expected") },
171→    { label: "Factual", value: formatScore(scores, "factuality") },
172→    { label: "NoHalluc", value: formatScore(scores, "no-hallucination") },
173→  ],
174→});
175→
176→function formatScore(scores: Array<{ name: string; score: number | null }>, name: string): string {
177→  const match = scores.find((s) => s.name === name);
178→  return match?.score !== null && match?.score !== undefined ? match.score.toFixed(2) : "N/A";
179→}
180→
181→async function runAnalyticsCase(testCase: AnalyticsTestCase): Promise<AnalyticsEvalOutput> {
182→  const context: ChatToolExecutionContext = {
183→    actor: "analytics_agent",
184→    workspaceRecord: seedResult.workspaceRecord,
185→    conversationRecord: new RecordId("conversation", "eval-analytics"),
186→    currentMessageRecord: new RecordId("message", `eval-${testCase.id}`),
187→    latestUserText: testCase.question,
188→  };
189→
190→  try {
191→    const result = await runAnalyticsAgent({
192→      analyticsSurreal,
193→      analyticsAgentModel,
194→      context,
195→      question: testCase.question,
196→    });
197→
198→    return {
199→      caseId: testCase.id,
200→      question: testCase.question,
201→      answer: result.answer,
202→      query_executed: result.query_executed,
203→      result_summary: result.result_summary,
204→      referenced_entities: result.referenced_entities,
205→      success: true,
206→    };
207→  } catch (error) {
208→    return {
209→      caseId: testCase.id,
210→      question: testCase.question,
211→      answer: "",
212→      query_executed: "",
213→      result_summary: "",
214→      referenced_entities: [],
215→      success: false,
216→      error: error instanceof Error ? error.message : String(error),
217→    };
218→  }
219→}
