176→export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
177→  const response = await fetch(url, init);
178→  if (!response.ok) {
179→    const body = await response.text();
180→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
181→  }
182→
183→  return (await response.json()) as T;
184→}
