186→async function waitForHealth(url: string, process: ReturnType<typeof Bun.spawn>, timeoutMs: number): Promise<void> {
187→  const start = Date.now();
188→
189→  while (Date.now() - start < timeoutMs) {
190→    if (typeof process.exitCode === "number") {
191→      throw new Error(`Smoke server exited early with code ${process.exitCode}`);
192→    }
193→
194→    try {
195→      const response = await fetch(`${url}/healthz`);
196→      if (response.ok) {
197→        return;
198→      }
199→    } catch {
200→      // Keep polling.
201→    }
202→
203→    await Bun.sleep(200);
204→  }
205→
206→  throw new Error(`Timed out waiting for smoke server health at ${url}/healthz`);
207→}
208→
209→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
210→  return await Promise.race([
211→    callback(),
212→    new Promise<T>((_, reject) => {
213→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
214→    }),
215→  ]);
216→}
