 5→export const entityRecallScorer = createScorer<GoldenCase, ExtractionEvalOutput, GoldenCase>({
 6→  name: "entity-recall",
 7→  description: "Percent of expected entities present in extraction output by kind and text/text_contains expectation.",
 8→  scorer: ({ output, expected }) => {
 9→    const expectedEntities = expected?.expectedEntities ?? [];
10→    if (expectedEntities.length === 0) {
11→      return { score: 1 };
12→    }
13→
14→    let matched = 0;
15→    for (const expectedEntity of expectedEntities) {
16→      const found = output.extractedEntities.some((entity) => matchesExpectedEntity(expectedEntity, entity, 0.5));
17→      if (found) {
18→        matched += 1;
19→      }
20→    }
21→
22→    return { score: matched / expectedEntities.length };
23→  },
24→});
