22→        return normalizedExtracted.some((entityText) => entityText.includes(phrase) || phrase.includes(entityText));
23→      });
24→
25→    return {
26→      score: matchedForbidden.length === 0 ? 1 : 0,
27→      metadata: matchedForbidden.length === 0 ? undefined : { matchedForbidden },
