18→          contextMessageIds: output.contextMessageIds,
19→        },
20→      };
21→    }
22→
23→    const matched = output.evidenceRows.some((row) => row.resolvedFromId === expectedMessageId);
24→    return {
25→      score: matched ? 1 : 0,
26→      metadata: matched
27→        ? undefined
28→        : {
29→            expectedResolvedFromId: expectedMessageId,
30→            actualResolvedFromIds: output.evidenceRows.map((row) => row.resolvedFromId),
31→          },
32→    };
33→  },
