 49→    { label: "Model", value: chatAgentModel },
 50→    { label: "Case", value: input.id },
 51→    { label: "ExpectedMin", value: input.expectedMinSuggestions ?? 1 },
 52→    { label: "Returned", value: output.suggestions.length },
 53→    { label: "Grounded", value: formatScoreCell(scoreByName(scores, "suggestion-grounding")) },
 54→    { label: "NoGeneric", value: formatScoreCell(scoreByName(scores, "no-generic-suggestions")) },
 55→    { label: "Count", value: formatScoreCell(scoreByName(scores, "suggestion-count")) },
 56→  ],
 57→});
