12→export const noGenericSuggestionsScorer = createScorer<SuggestionGoldenCase, SuggestionsEvalOutput, SuggestionGoldenCase>({
13→  name: "no-generic-suggestions",
14→  description: "Score 1 when case-specific forbidden suggestions are absent.",
15→  scorer: ({ output, expected }) => {
16→    const forbidden = (expected.forbiddenSuggestions ?? []).map((value) => normalize(value));
17→    if (forbidden.length === 0) {
18→      return { score: 1 };
19→    }
20→
21→    const matchedForbidden = output.suggestions.filter((suggestion) => {
22→      const normalizedSuggestion = normalize(suggestion);
23→      return forbidden.some((template) =>
24→        normalizedSuggestion === template || normalizedSuggestion.startsWith(`${template} `)
25→      );
26→    });
27→
28→    return {
29→      score: matchedForbidden.length === 0 ? 1 : 0,
30→      metadata: matchedForbidden.length === 0 ? undefined : { matchedForbidden },
31→    };
32→  },
33→});
