 48→export async function buildChatContext(input: {
 49→  surreal: Surreal;
 50→  conversationRecord: RecordId<"conversation", string>;
 51→  workspaceRecord: RecordId<"workspace", string>;
 52→  loaders?: ChatContextLoaders;
 53→  inheritedEntityIds?: RecordId[];
 54→  discussesRecord?: RecordId;
 55→  userMessageEmbedding?: number[];
 56→}): Promise<ChatContext> {
 57→  const loaders = input.loaders ?? {
 58→    listConversationEntities,
 59→    listWorkspaceProjectSummaries,
 60→    listWorkspaceRecentDecisions,
 61→    listWorkspaceOpenQuestions,
 62→    listWorkspaceOpenObservations,
 63→    loadOnboardingSummary,
 64→  };
 65→
 66→  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations, onboardingSummary] = await Promise.all([
 67→    loaders.listConversationEntities({
 68→      surreal: input.surreal,
 69→      conversationRecord: input.conversationRecord,
 70→      workspaceRecord: input.workspaceRecord,
 71→      limit: 60,
 72→      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 73→        ? { inheritedEntityIds: input.inheritedEntityIds }
 74→        : {}),
 75→    }),
 76→    loaders.listWorkspaceProjectSummaries({
 77→      surreal: input.surreal,
 78→      workspaceRecord: input.workspaceRecord,
 79→      limit: 20,
 80→    }),
 81→    loaders.listWorkspaceRecentDecisions({
 82→      surreal: input.surreal,
 83→      workspaceRecord: input.workspaceRecord,
 84→      limit: 12,
 85→    }),
 86→    loaders.listWorkspaceOpenQuestions({
 87→      surreal: input.surreal,
 88→      workspaceRecord: input.workspaceRecord,
 89→      limit: 12,
 90→    }),
 91→    loaders.listWorkspaceOpenObservations({
 92→      surreal: input.surreal,
 93→      workspaceRecord: input.workspaceRecord,
 94→      limit: 10,
 95→    }),
 96→    loaders.loadOnboardingSummary(input.surreal, input.workspaceRecord),
 97→  ]);
 98→
 99→  // Cross-conversation entity enrichment: find workspace entities relevant to the user's message
100→  let relevantEntities: RankedEntity[] | undefined;
101→  if (input.userMessageEmbedding) {
102→    const queryEmbedding = input.userMessageEmbedding;
103→    const conversationEntityIds = new Set(
104→      conversationEntities.map((e) => e.id),
105→    );
106→    const ranked = await searchEntitiesByEmbedding({
107→      surreal: input.surreal,
108→      workspaceRecord: input.workspaceRecord,
109→      queryEmbedding,
110→      limit: 15,
111→    });
112→    const filtered = ranked.filter((e) => !conversationEntityIds.has(e.id));
113→    if (filtered.length > 0) {
114→      relevantEntities = filtered.slice(0, 10);
115→    }
116→  }
117→
118→  let discussedEntity: DiscussedEntityContext | undefined;
119→  if (input.discussesRecord) {
120→    const entityRecord = input.discussesRecord as GraphEntityRecord;
121→    const name = await readEntityName(input.surreal, entityRecord);
122→    if (name) {
123→      const row = await input.surreal.select<Record<string, unknown>>(entityRecord);
124→      discussedEntity = {
125→        kind: entityRecord.table.name,
126→        name,
127→        ...(row && typeof row.status === "string" ? { status: row.status } : {}),
128→      };
129→    }
130→  }
131→
132→  return {
133→    conversationEntities,
134→    relevantEntities,
135→    workspaceSummary: {
136→      projects,
137→      recentDecisions,
138→      openQuestions,
139→      openObservations,
140→    },
141→    onboardingSummary,
142→    discussedEntity,
143→  };
144→}
