 12→export async function seedAnalyticsTestData(surreal: Surreal): Promise<AnalyticsSeedResult> {
 13→  const nextId = createDeterministicIdGenerator("analytics-eval");
 14→  const now = new Date();
 15→  const twoWeeksAgo = new Date(now.getTime() - 15 * 24 * 60 * 60 * 1000);
 16→  const oneMonthAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
 17→
 18→  // Workspace
 19→  const workspaceRecord = new RecordId("workspace", nextId());
 20→  await surreal.create(workspaceRecord).content({
 21→    name: "Analytics Eval Workspace",
 22→    status: "active",
 23→    onboarding_complete: true,
 24→    onboarding_turn_count: 5,
 25→    onboarding_summary_pending: false,
 26→    onboarding_started_at: oneMonthAgo,
 27→    created_at: oneMonthAgo,
 28→    updated_at: now,
 29→  });
 30→
 31→  // Owner
 32→  const ownerRecord = new RecordId("person", nextId());
 33→  await surreal.create(ownerRecord).content({
 34→    name: "Eval Owner",
 35→    created_at: oneMonthAgo,
 36→    updated_at: now,
 37→  });
 38→  await surreal
 39→    .relate(ownerRecord, new RecordId("member_of", nextId()), workspaceRecord, {
 40→      role: "owner",
 41→      added_at: oneMonthAgo,
 42→    })
 43→    .output("after");
 44→
 45→  // Projects
 46→  const projectA = new RecordId("project", nextId());
 47→  const projectB = new RecordId("project", nextId());
 48→  for (const [record, name] of [
 49→    [projectA, "Project Alpha"],
 50→    [projectB, "Project Beta"],
 51→  ] as const) {
 52→    await surreal.create(record).content({
 53→      name,
 54→      status: "active",
 55→      workspace: workspaceRecord,
 56→      created_at: oneMonthAgo,
 57→      updated_at: now,
 58→    });
 59→    await surreal
 60→      .relate(workspaceRecord, new RecordId("has_project", nextId()), record, {
 61→        added_at: oneMonthAgo,
 62→      })
 63→      .output("after");
 64→  }
 65→
 66→  // Features (3 total, 2 for project A, 1 for project B)
 67→  const features: RecordId<"feature", string>[] = [];
 68→  const featureNames = ["Auth System", "Billing Module", "Dashboard"];
 69→  const featureProjects = [projectA, projectA, projectB];
 70→  for (let i = 0; i < 3; i++) {
 71→    const featureRecord = new RecordId("feature", nextId()) as RecordId<"feature", string>;
 72→    await surreal.create(featureRecord).content({
 73→      name: featureNames[i],
 74→      status: "active",
 75→      created_at: oneMonthAgo,
 76→      updated_at: now,
 77→    });
 78→    await surreal
 79→      .relate(featureProjects[i], new RecordId("has_feature", nextId()), featureRecord, {
 80→        added_at: oneMonthAgo,
 81→      })
 82→      .output("after");
 83→    features.push(featureRecord);
 84→  }
 85→
 86→  // Tasks (10 total: 5 open, 3 closed, 2 blocked)
 87→  const taskStatuses = ["open", "open", "open", "open", "open", "closed", "closed", "closed", "blocked", "blocked"];
 88→  const taskTitles = [
 89→    "Implement login flow",
 90→    "Add password reset",
 91→    "Write auth tests",
 92→    "Design token refresh",
 93→    "Document auth API",
 94→    "Setup CI pipeline",
 95→    "Create DB schema",
 96→    "Configure linting",
 97→    "Integrate payment gateway",
 98→    "Build invoice generator",
 99→  ];
100→  const taskFeatures = [features[0], features[0], features[0], features[0], features[0], features[1], features[1], features[1], features[2], features[2]];
101→  const tasks: RecordId<"task", string>[] = [];
102→
103→  for (let i = 0; i < 10; i++) {
104→    const taskRecord = new RecordId("task", nextId()) as RecordId<"task", string>;
105→    await surreal.create(taskRecord).content({
106→      title: taskTitles[i],
107→      status: taskStatuses[i],
108→      workspace: workspaceRecord,
109→      created_at: oneMonthAgo,
110→      updated_at: now,
111→    });
112→    await surreal
113→      .relate(taskRecord, new RecordId("belongs_to", nextId()), taskFeatures[i], {
114→        added_at: oneMonthAgo,
115→      })
116→      .output("after");
117→    tasks.push(taskRecord);
118→  }
119→
120→  // Dependency chain: task[8] depends on task[5], task[9] depends on task[8]
121→  await surreal
122→    .relate(tasks[8], new RecordId("depends_on", nextId()), tasks[5], { type: "blocks", added_at: now })
123→    .output("after");
124→  await surreal
125→    .relate(tasks[9], new RecordId("depends_on", nextId()), tasks[8], { type: "blocks", added_at: now })
126→    .output("after");
127→
128→  // Decisions (5 total: 3 stale provisional, 2 confirmed)
129→  const decisionSummaries = [
130→    "Use JWT for authentication",
131→    "Deploy to AWS",
132→    "Use PostgreSQL for billing",
133→    "Adopt microservices architecture",
134→    "Use React for frontend",
135→  ];
136→  const decisionStatuses = ["provisional", "provisional", "provisional", "confirmed", "confirmed"];
137→  const decisionDates = [oneMonthAgo, twoWeeksAgo, oneMonthAgo, now, now];
138→
139→  for (let i = 0; i < 5; i++) {
140→    const decisionRecord = new RecordId("decision", nextId());
141→    await surreal.create(decisionRecord).content({
142→      summary: decisionSummaries[i],
143→      status: decisionStatuses[i],
144→      workspace: workspaceRecord,
145→      created_at: decisionDates[i],
146→      updated_at: decisionDates[i],
147→    });
148→    await surreal
149→      .relate(decisionRecord, new RecordId("belongs_to", nextId()), projectA, {
150→        added_at: decisionDates[i],
151→      })
152→      .output("after");
153→  }
154→
155→  // Observations (3 total: 2 open, 1 resolved)
156→  const observationTexts = [
157→    "Auth and billing timelines may conflict",
158→    "Dashboard feature lacks acceptance criteria",
159→    "CI pipeline latency resolved",
160→  ];
161→  const observationSeverities = ["warning", "info", "warning"];
162→  const observationStatuses = ["open", "open", "resolved"];
163→
164→  for (let i = 0; i < 3; i++) {
165→    const obsRecord = new RecordId("observation", nextId());
166→    await surreal.create(obsRecord).content({
167→      text: observationTexts[i],
168→      severity: observationSeverities[i],
169→      status: observationStatuses[i],
170→      source_agent: "pm_agent",
171→      workspace: workspaceRecord,
172→      created_at: now,
173→      updated_at: now,
174→    });
175→  }
176→
177→  return {
178→    workspaceRecord,
179→    projectRecords: [projectA, projectB],
180→    taskCount: { open: 5, closed: 3, blocked: 2 },
181→    staleDecisionCount: 3,
182→    openObservationCount: 2,
183→  };
184→}
