 8→export function createInvokePmAgentTool(deps: ChatAgentToolDeps) {
 9→  return tool({
10→    description:
11→      "Invoke the PM subagent — the single authority on tasks, features, and project status.",
12→    inputSchema: z.object({
13→      intent: z
14→        .enum(["plan_work", "check_status", "organize", "track_dependencies"])
15→        .describe(
16→          "plan_work: user discusses goals, features, or work to be done. check_status: user asks about progress, blockers, or project status. organize: user wants to restructure or re-prioritize. track_dependencies: user asks about blocked items or dependency chains.",
17→        ),
18→      context: z.string().min(1).describe("Conversation context for the PM agent"),
19→      project: z.string().optional().describe("Optional project scope"),
20→    }),
21→    execute: async (input, options) => {
22→      const context = requireToolContext(options);
23→
24→      try {
25→        return await runPmAgent({
26→          deps,
27→          context,
28→          intent: input.intent,
29→          conversationContext: input.context,
30→          ...(input.project ? { project: input.project } : {}),
31→        });
32→      } catch (error) {
33→        logError("tool.invoke_pm_agent.failed", "PM agent invocation failed", error, {
34→          intent: input.intent,
35→          workspace: context.workspaceRecord.toString(),
36→          conversation: context.conversationRecord.toString(),
37→        });
38→        throw error;
39→      }
