12→export function createCreateProvisionalDecisionTool(deps: ChatToolDeps) {
13→  return tool({
14→    description:
15→      "Create a provisional decision when no existing answer exists. Use after resolve_decision returns unresolved and the user wants to proceed.",
16→    inputSchema: z.object({
17→      name: z.string().min(1).describe("Concise decision name"),
18→      rationale: z.string().min(1).describe("Why this decision was made"),
19→      context: z
20→        .object({
21→          project: z.string().optional(),
22→          feature: z.string().optional(),
23→        })
24→        .optional(),
25→      options_considered: z.array(z.string().min(1)).optional(),
26→    }),
27→    execute: async (input, options) => {
28→      const context = requireToolContext(options);
29→      const now = new Date();
30→
31→      const projectRecord = input.context?.project
32→        ? await resolveWorkspaceProjectRecord({
33→            surreal: deps.surreal,
34→            workspaceRecord: context.workspaceRecord,
35→            projectInput: input.context.project,
36→          })
37→        : undefined;
38→
39→      const featureRecord = input.context?.feature
40→        ? await resolveWorkspaceFeatureRecord({
41→            surreal: deps.surreal,
42→            workspaceRecord: context.workspaceRecord,
43→            featureInput: input.context.feature,
44→          })
45→        : undefined;
46→
47→      const decisionRecord = await createDecisionRecord({
48→        surreal: deps.surreal,
49→        summary: input.name,
50→        status: "provisional",
51→        now,
52→        workspaceRecord: context.workspaceRecord,
53→        sourceMessageRecord: context.currentMessageRecord,
54→        rationale: input.rationale,
55→        ...(input.options_considered && input.options_considered.length > 0
56→          ? { optionsConsidered: input.options_considered }
57→          : {}),
58→        decidedByName: "chat_agent",
59→        ...(projectRecord ? { projectRecord } : {}),
60→        ...(featureRecord ? { featureRecord } : {}),
61→      });
62→
63→      await createExtractionProvenanceEdge({
64→        surreal: deps.surreal,
65→        sourceRecord: context.currentMessageRecord,
66→        targetRecord: decisionRecord,
67→        now,
68→        confidence: 0.9,
69→        model: deps.extractionModelId,
70→        fromText: input.name,
71→        evidence: context.latestUserText,
72→        evidenceSourceRecord: context.currentMessageRecord,
73→      });
74→
75→      return {
76→        decision_id: `decision:${decisionRecord.id as string}`,
77→        status: "provisional",
78→        review_required: true,
79→      };
80→    },
81→  });
82→}
