        listWorkspaceProjectSummaries: async () => [
          {
            id: "p-1",
            name: "Brain",
            activeTaskCount: 7,
          },
        ],
        listWorkspaceRecentDecisions: async () => [
          {
            id: "d-1",
            name: "Use token bucket for rate limiting",
            status: "provisional",
            project: "Brain",
          },
        ],
        listWorkspaceOpenQuestions: async () => [
